mapper.select:
SELECT c.*, m.movie_name, m.director, m.year, m.poster_url, m.genre, m.region
FROM movie_collection c
JOIN movie_public m ON c.movie_id = m.movie_id
WHERE c.user_id = #{userId}



    AND m.movie_name LIKE CONCAT('%', #{keyword}, '%')




    AND m.director LIKE CONCAT('%', #{director}, '%')




    AND c.personal_rating >= #{minRating}




    AND c.watch_status = #{watchStatus}




    AND m.region = #{region}




    AND FIND_IN_SET(#{genre}, REPLACE(m.genre, '、', ',')) > 0




    AND m.year >= #{minYear}


    AND m.year <= #{maxYear}




    AND c.category_id = #{categoryId}





        ORDER BY c.create_time DESC


        ORDER BY c.create_time ASC


        ORDER BY c.personal_rating DESC NULLS LAST


        ORDER BY c.personal_rating ASC NULLS LAST


        ORDER BY m.year DESC


        ORDER BY m.year ASC


        ORDER BY m.movie_name ASC


        ORDER BY m.movie_name DESC


        ORDER BY c.create_time DESC

